-- Migration 027: Job Role Taxonomy (imported from Airtable)
-- 84 job roles with ~791 synonyms across 4 families
-- Source: Airtable base apptFYaQLMnZo1y3y, table tblCPr1CEvjIhLhHI

-- Create job_roles table
CREATE TABLE IF NOT EXISTS job_roles (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name        TEXT NOT NULL UNIQUE,
  family      TEXT NOT NULL,  -- Management | Technology | Core Engineering | Others
  synonyms    TEXT[] DEFAULT '{}',
  airtable_id TEXT,
  created_at  TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_job_roles_family ON job_roles(family);
CREATE INDEX IF NOT EXISTS idx_job_roles_name ON job_roles(name);

-- RLS: allow read for authenticated users
ALTER TABLE job_roles ENABLE ROW LEVEL SECURITY;
CREATE POLICY "auth_read_job_roles" ON job_roles FOR SELECT TO authenticated USING (true);

-- Add job_role_id FK to jobs table for categorization during scraping
ALTER TABLE jobs ADD COLUMN IF NOT EXISTS job_role_id UUID REFERENCES job_roles(id);
CREATE INDEX IF NOT EXISTS idx_jobs_job_role ON jobs(job_role_id);

-- Seed data: all job roles with synonyms

-- Total: 84 roles, 791 synonyms
-- Family breakdown: Core Engineering=7, Management=38, Others=17, Technology=22